    const kitsRes = await pgReq('GET', `/rest/v1/itens_de_orcamento?${baseFilter}&kit=eq.true&select=id,orcamento_id,produto_id,quantidade,acrescimo,ambiente,descricao,descricao_personalizada,opcao_de_fornecimento,cadastro_para_troca,canvas_x,canvas_y,canvas_zone,canvas_zoom,congelar,duplicacao_solicitada,opcao_de_devolucao,removido,section,section_order_index`, null);
    if (kitsRes.statusCode !== 200 || !Array.isArray(kitsRes.body)) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to list kits: HTTP ${kitsRes.statusCode}` };
        return msg;
    }
    const kits = kitsRes.body;
    let childrenCreated = 0;
    let kitsExpanded = 0;
    const phaseAErrors = [];

    for (const kit of kits) {
        if (!kit.produto_id) continue;
        const childRes = await pgReq('GET', `/rest/v1/itens_de_kit?kit_id=eq.${encodeURIComponent(kit.produto_id)}&select=id,produto_id,quantidade`, null);
        if (childRes.statusCode !== 200 || !Array.isArray(childRes.body)) {
            phaseAErrors.push({ kitId: kit.id, stage: 'list-children', status: childRes.statusCode });
            continue;
        }
        const children = childRes.body;
        let anyChildCreated = false;
        for (const child of children) {
            if (!child.produto_id) continue;
            const newItem = {
                orcamento_id: kit.orcamento_id,
                produto_id: child.produto_id,
                quantidade: Number(kit.quantidade || 0) * Number(child.quantidade || 0),
                acrescimo: kit.acrescimo,
                ambiente: kit.ambiente,
                descricao: kit.descricao,
                descricao_personalizada: kit.descricao_personalizada,
                opcao_de_fornecimento: kit.opcao_de_fornecimento,
                cadastro_para_troca: kit.cadastro_para_troca,
                canvas_x: kit.canvas_x,
                canvas_y: kit.canvas_y,
                canvas_zone: kit.canvas_zone,
                canvas_zoom: kit.canvas_zoom,
                congelar: kit.congelar,
                duplicacao_solicitada: kit.duplicacao_solicitada,
                opcao_de_devolucao: kit.opcao_de_devolucao,
                removido: kit.removido,
                section: kit.section,
                section_order_index: kit.section_order_index,
                kit: false
            };
            const createRes = await pgReq('POST', '/rest/v1/itens_de_orcamento', newItem, { 'Prefer': 'return=representation' });
            if (createRes.statusCode >= 200 && createRes.statusCode < 300) {
                childrenCreated++;
                anyChildCreated = true;
            } else {
                phaseAErrors.push({ kitId: kit.id, childProdutoId: child.produto_id, stage: 'create-child', status: createRes.statusCode });
            }
        }
        if (anyChildCreated) {
            const delRes = await pgReq('DELETE', `/rest/v1/itens_de_orcamento?id=eq.${encodeURIComponent(kit.id)}`, null);
            if (delRes.statusCode >= 200 && delRes.statusCode < 300) {
                kitsExpanded++;
            } else {
                phaseAErrors.push({ kitId: kit.id, stage: 'delete-original', status: delRes.statusCode });
            }
        }
    }

    // Phase B: consolidate duplicates by (produto_id, section, ambiente)
    const allRes = await pgReq('GET', `/rest/v1/itens_de_orcamento?${baseFilter}&select=id,produto_id,section,ambiente,quantidade,acrescimo,descricao,descricao_personalizada,opcao_de_fornecimento,cadastro_para_troca,canvas_x,canvas_y,canvas_zone,canvas_zoom,congelar,duplicacao_solicitada,opcao_de_devolucao,removido,section_order_index,orcamento_id`, null);
    if (allRes.statusCode !== 200 || !Array.isArray(allRes.body)) {
        msg.statusCode = 207;
        msg.payload = { ok: true, phaseA: { kitsExpanded, childrenCreated, errors: phaseAErrors }, phaseB: { skipped: true, reason: `list-failed-${allRes.statusCode}` } };
        return msg;
    }
    const all = allRes.body;
    const groups = new Map();
    for (const it of all) {
        if (!it.produto_id) continue;
        const key = `${it.produto_id}||${it.section || ''}||${it.ambiente || ''}`;
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key).push(it);
    }
    let consolidated = 0;
    let consolidatedDeleted = 0;
    const phaseBErrors = [];
    for (const [key, items] of groups.entries()) {
        if (items.length < 2) continue;
        const sumQty = items.reduce((a, it) => a + Number(it.quantidade || 0), 0);
        const tmpl = items[0];
        const newItem = {
            orcamento_id: tmpl.orcamento_id,
            produto_id: tmpl.produto_id,
            quantidade: sumQty,
            acrescimo: tmpl.acrescimo,
            ambiente: tmpl.ambiente,
            descricao: tmpl.descricao,
            descricao_personalizada: tmpl.descricao_personalizada,
            opcao_de_fornecimento: tmpl.opcao_de_fornecimento,
            cadastro_para_troca: tmpl.cadastro_para_troca,
            canvas_x: tmpl.canvas_x,
            canvas_y: tmpl.canvas_y,
            canvas_zone: tmpl.canvas_zone,
            canvas_zoom: tmpl.canvas_zoom,
            congelar: tmpl.congelar,
            duplicacao_solicitada: tmpl.duplicacao_solicitada,
            opcao_de_devolucao: tmpl.opcao_de_devolucao,
            removido: tmpl.removido,
            section: tmpl.section,
            section_order_index: tmpl.section_order_index,
            kit: false
        };
        const cRes = await pgReq('POST', '/rest/v1/itens_de_orcamento', newItem, { 'Prefer': 'return=representation' });
        if (cRes.statusCode < 200 || cRes.statusCode >= 300) {
            phaseBErrors.push({ key, stage: 'create-consolidated', status: cRes.statusCode });
            continue;
        }
        consolidated++;
        for (const it of items) {
            const dRes = await pgReq('DELETE', `/rest/v1/itens_de_orcamento?id=eq.${encodeURIComponent(it.id)}`, null);
            if (dRes.statusCode >= 200 && dRes.statusCode < 300) {
                consolidatedDeleted++;
            } else {
                phaseBErrors.push({ itemId: it.id, stage: 'delete-dup', status: dRes.statusCode });
            }
        }
    }

    msg.statusCode = 200;
    msg.payload = {
        ok: true,
        orcamentoId: orcamentoId,
        phaseA: { kitsFound: kits.length, kitsExpanded, childrenCreated, errors: phaseAErrors.length },
        phaseB: { groupsProcessed: groups.size, consolidated, consolidatedDeleted, errors: phaseBErrors.length }
    };
    return msg;
} catch (err) {
    node.error('[desmembrar-kits] ' + (err && err.message) + (err && err.stack ? '\n' + err.stack : ''), msg);
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Internal error' };
    return msg;
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[desmembrar-kits] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error', flow: 'desmembrar-kits', timestamp: new Date().toISOString() };
return msg;
